const input = $input.first().json;


let queryBody;
if (!input.cursor || input.cursor === '') {
  const query = `{boards(ids:8707938312){items_page(limit:500 query_params: {rules: [{column_id: "status",compare_value: [3]}]}){cursor items{id name column_values(ids: ["board_relation_mkpk7nj7", "status"]){id text value ... on BoardRelationValue{display_value linked_items{id name column_values {id text value}}}}}}}}`;
  queryBody = JSON.stringify({ query });
} else {
  const query = `{next_items_page(limit:500 cursor:"${input.cursor}"){cursor items{id name column_values(ids: ["board_relation_mkpk7nj7", "status"]){id text value ... on BoardRelationValue{display_value linked_items{id name column_values {id text value}}}}}}}`;
  queryBody = JSON.stringify({ query });
}

return [{
  json: {
    allItems: input.allItems,
    pageIndex: input.pageIndex,
    queryBody
  }
}];

const input = $('Build App Pipeline Query').first().json;
const httpResp = $input.first().json;

// Ensure prevItems is always an array
let prevItems = [];
try {
  const parsed = JSON.parse(input.allItems || '[]');
  prevItems = Array.isArray(parsed) ? parsed : [];
} catch {
  prevItems = [];
}

// Extract page items and cursor safely
const data = httpResp.data;
const pageItems = data?.boards?.[0]?.items_page?.items
                || data?.next_items_page?.items
                || [];
const newCursor = data?.boards?.[0]?.items_page?.cursor
                || data?.next_items_page?.cursor
                || null;

// Merge items and increment page index
const allItems = [...prevItems, ...pageItems];
const pageIndex = (input.pageIndex || 0) + 1;

return [{
  json: {
    cursor: newCursor || "",
    pageIndex,
    hasMore: !!newCursor,
    allItems: JSON.stringify(allItems),
  }
}];

// Helper functions
function colText(item, colId) {
  const col = (item.column_values || []).find(c => c.id === colId);
  return col ? (col.text || '') : '';
}

function colLinkedItems(item, colId) {
  const col = (item.column_values || []).find(c => c.id === colId);
  return col && col.linked_items ? col.linked_items : [];
}

// Get input
const input = $input.first().json;

// Ensure allItems is an array
let allItems = [];
try {
  allItems = typeof input.allItems === 'string' ? JSON.parse(input.allItems) : input.allItems;
  if (!Array.isArray(allItems)) allItems = [];
} catch {
  allItems = [];
}

const result = [];

// Loop using for…of
for (const item of allItems) {
  const itemId = item.id;

  const linkedItems = colLinkedItems(item, "board_relation_mkpk7nj7");
  for (const linkedItem of linkedItems) {
    const linkedItemId = linkedItem.id;
    const sentDate = colText(linkedItem, "date_mkpkc1ad");

    result.push({
      item_id: itemId,
      linked_item_id: linkedItemId,
      sent_date: sentDate
    });
  }
}

// Return in n8n format
return result.map(r => ({ json: {items: r} }));
